local function _b64d(d)
    local b='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    d=d:gsub('[^'..b..'=]','')
    return(d:gsub('.',function(x)
        if x=='='then return''end
        local r,f='',(b:find(x)-1)
        for i=6,1,-1 do r=r..(f%2^i-f%2^(i-1)>0 and'1'or'0')end
        return r
    end):gsub('%d%d%d?%d?%d?%d?%d?%d?',function(x)
        if#x~=8 then return''end
        local c=0
        for i=1,8 do c=c+(x:sub(i,i)=='1'and 2^(8-i)or 0)end
        return string.char(c)
    end))
end

local _xor
if bit32 and bit32.bxor then
    _xor=bit32.bxor
elseif bit and bit.bxor then
    _xor=bit.bxor
else
    _xor=function(a,b)
        local r,p=0,1
        for i=0,7 do
            local a1,b1=a%2,b%2
            if a1~=b1 then r=r+p end
            a,b,p=math.floor(a/2),math.floor(b/2),p*2
        end
        return r
    end
end

local _r=table.concat(_D)
_r=_r:reverse()
local _raw=_b64d(_r)
local _key=_b64d(_K)
local _out={}
for i=1,#_raw do
    _out[i]=string.char(_xor(string.byte(_raw,i),string.byte(_key,((i-1)%#_key)+1)))
end
local _src=table.concat(_out)
local _fn,_err=loadstring(_src)
if _fn then _fn() else warn("[GAG] Load error: "..tostring(_err)) end
